import{_ as s,o as i,c as a,a2 as l}from"./chunks/framework.BRk9mohw.js";const k=JSON.parse('{"title":"命令队列","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/queue.md","filePath":"concepts/queue.md"}'),o={name:"concepts/queue.md"};function t(n,e,d,c,h,r){return i(),a("div",null,[...e[0]||(e[0]=[l(`<h1 id="命令队列" tabindex="-1">命令队列 <a class="header-anchor" href="#命令队列" aria-label="Permalink to &quot;命令队列&quot;">​</a></h1><h1 id="命令队列-2026-01-16" tabindex="-1">命令队列 (2026-01-16) <a class="header-anchor" href="#命令队列-2026-01-16" aria-label="Permalink to &quot;命令队列 (2026-01-16)&quot;">​</a></h1><p>我们通过一个微小的进程内队列序列化入站自动回复运行（所有渠道），以防止多个代理运行碰撞，同时仍允许跨会话安全并行。</p><h2 id="为什么" tabindex="-1">为什么 <a class="header-anchor" href="#为什么" aria-label="Permalink to &quot;为什么&quot;">​</a></h2><ul><li>自动回复运行可能很昂贵（LLM 调用），并且当多个入站消息同时到达时会碰撞。</li><li>序列化避免争夺共享资源（会话文件、日志、CLI stdin）并减少上游速率限制的可能性。</li></ul><h2 id="工作原理" tabindex="-1">工作原理 <a class="header-anchor" href="#工作原理" aria-label="Permalink to &quot;工作原理&quot;">​</a></h2><ul><li>通道感知的 FIFO 队列以可配置的并发上限排出每个通道（默认未配置通道为 1；main 默认为 4，subagent 默认为 8）。</li><li><code>runEmbeddedPiAgent</code> 按<strong>会话键</strong>入队（通道 <code>session:&lt;key&gt;</code>）以保证每个会话只有一个活动运行。</li><li>然后每个会话运行排队到<strong>全局通道</strong>（默认 <code>main</code>），以便总体并行度由 <code>agents.defaults.maxConcurrent</code> 限制。</li><li>启用详细日志时，排队的运行如果在开始前等待超过 ~2s 会发出简短通知。</li><li>排队的消息仍会在入队时立即触发打字指示器（当渠道支持时），因此在您等待轮次时用户体验不变。</li></ul><h2 id="队列模式-按渠道" tabindex="-1">队列模式（按渠道） <a class="header-anchor" href="#队列模式-按渠道" aria-label="Permalink to &quot;队列模式（按渠道）&quot;">​</a></h2><p>入站消息可以控制当前运行、等待后续轮次，或两者兼做：</p><ul><li><code>steer</code>：立即注入当前运行（在下一个工具边界后取消挂起的工具调用）。如果不流式传输，回退到 followup。</li><li><code>followup</code>：在当前运行结束后排队到下一个代理轮次。</li><li><code>collect</code>：将所有排队的消息合并为<strong>单个</strong>后续轮次（默认）。如果消息针对不同渠道/线程，它们单独排出以保留路由。</li><li><code>steer-backlog</code>（又名 <code>steer+backlog</code>）：现在转向<strong>并</strong>保留消息以进行后续轮次。</li><li><code>interrupt</code>（旧版）：中止该会话的活动运行，然后运行最新消息。</li><li><code>queue</code>（旧版别名）：与 <code>steer</code> 相同。</li></ul><p>Steer-backlog 意味着您可以在转向运行后获得后续回复，因此流式传输表面可能看起来像重复项。如果您希望每个入站消息有一个回复，请优先使用 <code>collect</code>/<code>steer</code>。 发送 <code>/queue collect</code> 作为独立命令（每会话）或设置 <code>messages.queue.byChannel.discord: &quot;collect&quot;</code>。</p><p>默认值（配置中未设置时）：</p><ul><li>所有表面 → <code>collect</code></li></ul><p>通过 <code>messages.queue</code> 全局或按渠道配置：</p><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  messages</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    queue</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      mode</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;collect&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      debounceMs</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      cap</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">20</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      drop</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;summarize&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      byChannel</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">discord</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;collect&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h2 id="队列选项" tabindex="-1">队列选项 <a class="header-anchor" href="#队列选项" aria-label="Permalink to &quot;队列选项&quot;">​</a></h2><p>选项适用于 <code>followup</code>、<code>collect</code> 和 <code>steer-backlog</code>（以及 <code>steer</code> 回退到 followup 时）：</p><ul><li><code>debounceMs</code>：在开始后续轮次之前等待安静（防止&quot;继续，继续&quot;）。</li><li><code>cap</code>：每个会话的最大排队消息数。</li><li><code>drop</code>：溢出策略（<code>old</code>、<code>new</code>、<code>summarize</code>）。</li></ul><p>Summarize 保留被丢弃消息的简短项目符号列表，并将其作为合成后续提示注入。 默认值：<code>debounceMs: 1000</code>、<code>cap: 20</code>、<code>drop: summarize</code>。</p><h2 id="每会话覆盖" tabindex="-1">每会话覆盖 <a class="header-anchor" href="#每会话覆盖" aria-label="Permalink to &quot;每会话覆盖&quot;">​</a></h2><ul><li>发送 <code>/queue &lt;mode&gt;</code> 作为独立命令以存储当前会话的模式。</li><li>可以组合选项：<code>/queue collect debounce:2s cap:25 drop:summarize</code></li><li><code>/queue default</code> 或 <code>/queue reset</code> 清除会话覆盖。</li></ul><h2 id="范围和保证" tabindex="-1">范围和保证 <a class="header-anchor" href="#范围和保证" aria-label="Permalink to &quot;范围和保证&quot;">​</a></h2><ul><li>适用于使用网关回复管道的所有入站渠道的自动回复代理运行（WhatsApp web、Telegram、Slack、Discord、Signal、iMessage、webchat 等）。</li><li>默认通道（<code>main</code>）对于入站 + 主心跳是进程范围的；设置 <code>agents.defaults.maxConcurrent</code> 以允许多个会话并行。</li><li>可能存在其他通道（例如 <code>cron</code>、<code>subagent</code>），因此后台作业可以并行运行而不会阻塞入站回复。</li><li>每会话通道保证一次只有一个代理运行接触给定会话。</li><li>无外部依赖或后台工作线程；纯 TypeScript + promises。</li></ul><h2 id="故障排除" tabindex="-1">故障排除 <a class="header-anchor" href="#故障排除" aria-label="Permalink to &quot;故障排除&quot;">​</a></h2><ul><li>如果命令看起来卡住了，启用详细日志并查找&quot;queued for …ms&quot;行以确认队列正在排出。</li><li>如果需要队列深度，启用详细日志并观察队列计时行。</li></ul>`,25)])])}const u=s(o,[["render",t]]);export{k as __pageData,u as default};
